VALUES
  ('dietitian-moex-10714', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列何者為影響血壓的相關因素？ 腎上腺素使心輸出降氐，進而使平均動脈壓下降  紅血球的量影響血液黏稠度，進而影響總血管周邊阻力 心跳速率和總血管周邊阻力決定心輸出  心輸出增加同時總血管周邊阻力降低時，平均動脈壓最高', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "cc2d54fbf051", "answer_pdf_sha1": "dfeb01e9d1ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10715', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '慢性腎衰竭的病人常有貧血的症狀是因為缺乏什麼？ 顆粒性細胞群落刺激因子（Granulocyte colony-stimulating factor） 多效生長因子（Multipotent growth factor） 紅血球生成素（Erythropoietin） 介白質（Interleukin）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "cc2d54fbf051", "answer_pdf_sha1": "dfeb01e9d1ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10716', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列何者為婦女停經後的生理變化？ 腦下垂體活動停止，使得卵巢分泌的雌二醇（Estradiol）降低 卵巢內的濾泡耗盡，但腦下垂體分泌至血液中的濾泡刺激素（FSH）卻上升 血液中的弱效動情激素（Estrogen）主要由肝臟製造分泌而來 脂肪組織較少的婦女血液中動情激素的濃度較高', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "cc2d54fbf051", "answer_pdf_sha1": "dfeb01e9d1ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10717', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '有關內分泌腺製造之激素，下列敘述何者正確？ 腦下垂體前葉製造生長激素（Growth hormone）  胎盤製造催產素（Oxytocin） 胰臟製造類胰島素生長因子（Insulin-like growth factors）  腎上腺皮質製造腎上腺素（Epinephrine） （請接背面）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "cc2d54fbf051", "answer_pdf_sha1": "dfeb01e9d1ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10718', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '年第一次專門職業及技術人員高等暨普通考試醫事人員、 全一張 （背面） 中醫師、心理師、呼吸治療師、營養師、獸醫人員考試試題 等    別 ：高等考試 類    科 ：營養師 科    目 ：生理學與生物化學', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "cc2d54fbf051", "answer_pdf_sha1": "dfeb01e9d1ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 94, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10719', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '膽固醇代謝後可以形成何種激素？ 腎上腺素（Adrenaline）    心房利尿鈉激素（Atrial natriuretic hormone） 抗利尿激素（Antidiuretic hormone）  醛固酮（Aldosterone）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "cc2d54fbf051", "answer_pdf_sha1": "dfeb01e9d1ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10720', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '有關生長激素（Growth hormone），下列敘述何者正確？ 壓力和低血糖會刺激生長激素的分泌  生長激素在白天分泌量達到最高 生長激素是影響胎兒生長發育最主要的荷爾蒙  生長激素的分泌隨年齡慢慢增加至老年為止', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "cc2d54fbf051", "answer_pdf_sha1": "dfeb01e9d1ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10721', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '有關甲狀腺素的敘述，下列何者正確？ 降低身體的代謝速率    促進熱量的消耗而有產熱作用 是一個含碘的類固醇激素    會促進副交感神經系統作用', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "cc2d54fbf051", "answer_pdf_sha1": "dfeb01e9d1ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10722', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '以下那一個連續性的敘述，最能表示腸胃道將可被人體利用的物質由體外運送到體內所需要進行的功能？ 消化、過濾、分泌、再吸收  消化、傳導、調節、整合  消化、分泌、吸收、運動  消化、代謝、合成、儲存', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "cc2d54fbf051", "answer_pdf_sha1": "dfeb01e9d1ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10723', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '老年人發生便秘主要是大腸的運動功能下降，其原因為何？ 胃黏膜平衡受損  小腸消化酵素分泌障礙  大腸的腸神經系統受損  肛門括約肌管制障礙', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "cc2d54fbf051", "answer_pdf_sha1": "dfeb01e9d1ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
